const now = DateTime.now();
const endDate = now.minus({ days: 2 });
const startDate = endDate.minus({ days: 6 });
return [{ json: {
  startDate: startDate.toFormat('yyyy-MM-dd'),
  endDate: endDate.toFormat('yyyy-MM-dd')
}}];

const url = $env.SUPABASE_URL;
const key = $env.SUPABASE_SERVICE_ROLE_KEY;
if (!url || !key) return [{ json: { previousAudits: [], trendWeeks: 0 } }];
try {
  const resp = await this.helpers.httpRequest({
    method: 'GET',
    url: url + '/rest/v1/audit_results?type=eq.seo&order=created_at.desc&limit=4',
    headers: { 'apikey': key, 'Authorization': 'Bearer ' + key }
  });
  return [{ json: { previousAudits: resp || [], trendWeeks: (resp || []).length } }];
} catch(e) {
  return [{ json: { previousAudits: [], trendWeeks: 0, fetchError: e.message } }];
}

const gscData = $('GSC Queries').first().json;
const ga4Data = $('GA4 Pages').first().json;

const gscRows = (gscData.rows || []).map(r => ({
  query: r.keys[0], page: r.keys[1], device: r.keys[2], clicks: r.clicks,
  impressions: r.impressions, ctr: +(r.ctr * 100).toFixed(1),
  position: +r.position.toFixed(1)
}));

const ga4Rows = (ga4Data.rows || []).map(r => ({
  page: r.dimensionValues[0].value,
  users: +r.metricValues[0].value,
  sessions: +r.metricValues[1].value,
  pageviews: +r.metricValues[2].value,
  bounce: +(+r.metricValues[3].value * 100).toFixed(1),
  duration: Math.round(+r.metricValues[4].value),
  conversions: +r.metricValues[5].value
}));

const pages = [
  { id: 8, url: '/', name: 'Home' },
  { id: 21, url: '/koogid', name: 'Koogid' },
  { id: 3133, url: '/koogid-eritellimusel', name: 'Custom Kitchens' },
  { id: 2465, url: '/kontakt', name: 'Kontakt' },
  { id: 6409, url: '/faq', name: 'FAQ' },
  { id: 25, url: '/hinnaparing', name: 'Hinnaparing' },
  { id: 5800, url: '/fassaadid', name: 'Fassaadid' },
  { id: 2530, url: '/materjalid', name: 'Materjalid' },
  { id: 2776, url: '/toopinnad', name: 'Toopinnad' },
  { id: 3010, url: '/valmistamine', name: 'Valmistamine' },
  { id: 2706, url: '/meie-furnituur', name: 'Furnituur' },
  { id: 2619, url: '/sahtlid', name: 'Sahtlid' },
  { id: 2651, url: '/nurgamehhanismid', name: 'Nurgamehhanismid' },
  { id: 536, url: '/tostemehhanismid', name: 'Tostemehhanismid' },
  { id: 2674, url: '/ladustamissusteemid', name: 'Ladustamissusteemid' },
  { id: 6309, url: '/fassaadid/egger-fassaadid', name: 'Egger Fassaadid' },
  { id: 5802, url: '/fassaadid/egger', name: 'Egger' },
  { id: 5804, url: '/fassaadid/fenix', name: 'Fenix' },
  { id: 6291, url: '/fassaadid/egger-kivi', name: 'Egger Kivi' },
  { id: 6293, url: '/fassaadid/egger-puit', name: 'Egger Puit' },
  { id: 6295, url: '/fassaadid/egger-monokroom', name: 'Egger Monokroom' },
  { id: 2943, url: '/toopinnad/laminaadist-toopinnad', name: 'Laminaat' },
  { id: 2951, url: '/toopinnad/kividest-toopinnad', name: 'Kivi Toopinnad' },
  { id: 6335, url: '/toopinnad/hpl-tootasapinnad', name: 'HPL' },
  { id: 0, url: '/blogi', name: 'Blogi' }
];

const results = [];
const delay = ms => new Promise(r => setTimeout(r, ms));

for (const page of pages) {
  let score = 0;
  const issues = [];
  const checks = {};

  try {
    const html = await this.helpers.httpRequest({ method: 'GET', url: 'https://studiokook.ee' + page.url, encoding: 'utf-8' });
    const htmlSize = Buffer.byteLength(html, 'utf8');
    checks.htmlSizeKB = Math.round(htmlSize / 1024);

    const titleMatch = html.match(/<title[^>]*>([^<]+)<\/title>/i);
    const title = titleMatch ? titleMatch[1].trim() : '';
    checks.title = title; checks.titleLength = title.length;
    if (!title) issues.push('NO_TITLE');
    else if (title.length < 25) { issues.push('TITLE_TOO_SHORT'); score += 4; }
    else if (title.length > 60) { issues.push('TITLE_TOO_LONG'); score += 8; }
    else score += 12;

    const descMatch = html.match(/<meta[^>]*name=["']description["'][^>]*content=["']([^"']*?)["']/i) || html.match(/<meta[^>]*content=["']([^"']*?)["'][^>]*name=["']description["']/i);
    const desc = descMatch ? descMatch[1].trim() : '';
    checks.description = desc; checks.descLength = desc.length;
    if (!desc) issues.push('NO_META_DESCRIPTION');
    else if (desc.length < 80) { issues.push('DESC_TOO_SHORT'); score += 6; }
    else if (desc.length > 160) { issues.push('DESC_TOO_LONG'); score += 8; }
    else score += 12;

    const h1s = html.match(/<h1[^>]*>[\s\S]*?<\/h1>/gi) || [];
    checks.h1Count = h1s.length;
    if (h1s.length === 0) issues.push('NO_H1');
    else if (h1s.length > 1) { issues.push('MULTIPLE_H1'); score += 4; }
    else score += 8;

    const h2s = html.match(/<h2[^>]*>[\s\S]*?<\/h2>/gi) || [];
    checks.h2Count = h2s.length;
    if (h2s.length === 0) issues.push('NO_H2_HEADINGS');
    else if (h2s.length < 2) score += 4;
    else score += 8;

    const imgs = html.match(/<img[^>]*>/gi) || [];
    const realImgs = imgs.filter(i => !i.includes('data:image'));
    const base64Imgs = imgs.filter(i => i.includes('data:image'));
    checks.imgTotal = imgs.length; checks.imgReal = realImgs.length; checks.imgBase64 = base64Imgs.length;
    let ma=0,md=0,mj=0;
    for (const img of realImgs) {
      if (!img.match(/alt=["'][^"']+["']/)) ma++;
      if (!img.includes('width=')) md++;
      if (img.match(/\.jpe?g["'?]/i) && !img.includes('srcset')) mj++;
    }
    checks.imgMissingAlt=ma; checks.imgMissingDim=md; checks.imgJpgNoWebp=mj;
    let imgScore = 12;
    if (ma>3) { imgScore-=4; issues.push('IMAGES_MISSING_ALT: '+ma); }
    if (md>3) { imgScore-=3; issues.push('IMAGES_MISSING_DIMENSIONS: '+md); }
    if (base64Imgs.length>10) { imgScore-=3; issues.push('EXCESSIVE_BASE64: '+base64Imgs.length); }
    if (mj>5) { imgScore-=2; issues.push('JPG_WITHOUT_WEBP: '+mj); }
    score += Math.max(0, imgScore);

    const schemas = html.match(/<script[^>]*type=["']application\/ld\+json["'][^>]*>[\s\S]*?<\/script>/gi) || [];
    checks.schemaCount = schemas.length;
    const schemaTypes = [];
    for (const s of schemas) { try { const j = JSON.parse(s.replace(/<[^>]+>/g,'')); schemaTypes.push(j['@type']||(j['@graph']?'Graph':'?')); } catch{} }
    checks.schemaTypes = schemaTypes;
    if (!schemas.length) issues.push('NO_STRUCTURED_DATA');
    else if (schemaTypes.includes('LocalBusiness')||schemaTypes.includes('FAQPage')) score+=8;
    else score+=5;

    if (htmlSize>500000) issues.push('HTML_TOO_LARGE: '+checks.htmlSizeKB+'KB');
    else if (htmlSize>300000) { issues.push('HTML_LARGE: '+checks.htmlSizeKB+'KB'); score+=4; }
    else score+=8;

    const il = (html.match(/href=["']https?:\/\/studiokook\.ee[^"']*/gi)||[]).length + (html.match(/href=["']\/[^"']*/gi)||[]).length;
    checks.internalLinks = il;
    if (il<3) issues.push('FEW_INTERNAL_LINKS'); else score+=5;

    checks.hasCanonical = !!html.match(/<link[^>]*rel=["']canonical["']/i);
    if (!checks.hasCanonical) issues.push('NO_CANONICAL'); else score+=5;

    const ogT=!!html.match(/<meta[^>]*property=["']og:title["']/i);
    const ogD=!!html.match(/<meta[^>]*property=["']og:description["']/i);
    const ogI=!!html.match(/<meta[^>]*property=["']og:image["']/i);
    checks.hasOgTitle=ogT; checks.hasOgDesc=ogD; checks.hasOgImage=ogI;
    if(!ogT||!ogD) issues.push('MISSING_OG_TAGS');
    if(ogT&&ogD&&ogI) score+=5; else if(ogT||ogD) score+=2;

    // Hreflang
    const hTags = html.match(/<link[^>]*hreflang=[^>]*>/gi) || [];
    const hMap = {};
    for (const t of hTags) { const l=t.match(/hreflang=["']([^"']+)["']/i); const h=t.match(/href=["']([^"']+)["']/i); if(l&&h) hMap[l[1]]=h[1]; }
    const missing = ['x-default','et','ru','en','fi'].filter(l=>!hMap[l]);
    checks.hreflang=hMap; checks.missingHreflang=missing;
    if(missing.length) issues.push('MISSING_HREFLANG: '+missing.join(',')); else score+=5;

    // Translation: lightweight HEAD-only check
    const tr = { et: 200 };
    for (const lang of ['ru','en','fi']) {
      const u = page.url==='/' ? 'https://studiokook.ee/'+lang+'/' : 'https://studiokook.ee/'+lang+page.url;
      try { await this.helpers.httpRequest({ method:'HEAD', url:u }); tr[lang]=200; } catch(e) { tr[lang]=e.message.includes('404')?404:0; }
    }
    checks.translations=tr;
    const tc = Object.values(tr).filter(s=>s===200).length;
    checks.translationCoverage = Math.round((tc/4)*100);
    if(tc<4) issues.push('MISSING_TRANSLATIONS: '+Object.entries(tr).filter(([,s])=>s!==200).map(([l])=>l).join(','));
    else score+=5;

    const pageGsc = gscRows.filter(r => { const u=r.page||''; if(page.url==='/') return u.match(/studiokook\.ee\/?([?#].*)?$/); return u.includes('studiokook.ee'+page.url); }).sort((a,b)=>b.impressions-a.impressions).slice(0,5);
    const pageGa4 = ga4Rows.find(r => { if(page.url==='/') return r.page==='/'||r.page===''; return r.page===page.url||r.page===page.url+'/'; }) || {users:0,sessions:0,pageviews:0,bounce:0,duration:0,conversions:0};

    results.push({ page_id:page.id, url:page.url, name:page.name, score:Math.min(100,score), issues, checks, currentSeo:{title,description:desc}, gscQueries:pageGsc, ga4Metrics:pageGa4 });
    // Free memory
  } catch(e) {
    const st = (e.message.includes('301')||e.message.includes('302')) ? 'redirect' : 'error';
    results.push({ page_id:page.id, url:page.url, name:page.name, score:0, issues:[st==='redirect'?'REDIRECT':'FETCH_ERROR: '+e.message.slice(0,60)], checks:{}, currentSeo:{}, gscQueries:[], ga4Metrics:{}, status:st });
  }
  await delay(200);
}

const active = results.filter(r=>r.status!=='redirect'&&r.status!=='error');
const avgScore = active.length ? Math.round(active.reduce((s,r)=>s+r.score,0)/active.length) : 0;
const totalIssues = results.reduce((s,r)=>s+r.issues.length,0);

return [{ json: { date: DateTime.now().toFormat('yyyy-MM-dd'), avgScore, totalIssues, pageCount: pages.length, results, worst: [...active].sort((a,b)=>a.score-b.score).slice(0,5).map(w=>w.name+' ('+w.score+')'), best: [...active].sort((a,b)=>b.score-a.score).slice(0,5).map(b=>b.name+' ('+b.score+')') } }];

const audit = $('Audit All Pages').first().json;
const pages = (audit.results || []).filter(r => r.status !== 'redirect' && r.status !== 'error').slice(0, 8);
const cwvResults = [];
const delay = ms => new Promise(r => setTimeout(r, ms));

for (const page of pages) {
  const fullUrl = 'https://studiokook.ee' + page.url;
  const pageResult = { url: page.url, name: page.name, mobile: null, desktop: null };

  try {
    const apiUrl = 'https://www.googleapis.com/pagespeedonline/v5/runPagespeed?url=' + encodeURIComponent(fullUrl) + '&strategy=mobile&category=performance';
    const resp = await this.helpers.httpRequest({ method: 'GET', url: apiUrl });
    const audits = resp.lighthouseResult?.audits || {};
    pageResult.mobile = {
      performanceScore: Math.round((resp.lighthouseResult?.categories?.performance?.score || 0) * 100),
      lcp: audits['largest-contentful-paint']?.numericValue || null,
      cls: audits['cumulative-layout-shift']?.numericValue || null,
      tbt: audits['total-blocking-time']?.numericValue || null,
      fcp: audits['first-contentful-paint']?.numericValue || null
    };
  } catch(e) {
    if (e.message.includes('429')) {
      await delay(15000);
      try {
        const apiUrl = 'https://www.googleapis.com/pagespeedonline/v5/runPagespeed?url=' + encodeURIComponent(fullUrl) + '&strategy=mobile&category=performance';
        const resp = await this.helpers.httpRequest({ method: 'GET', url: apiUrl });
        const audits = resp.lighthouseResult?.audits || {};
        pageResult.mobile = {
          performanceScore: Math.round((resp.lighthouseResult?.categories?.performance?.score || 0) * 100),
          lcp: audits['largest-contentful-paint']?.numericValue || null,
          cls: audits['cumulative-layout-shift']?.numericValue || null,
          tbt: audits['total-blocking-time']?.numericValue || null,
          fcp: audits['first-contentful-paint']?.numericValue || null
        };
      } catch(e2) { pageResult.mobile = { error: e2.message.slice(0, 80) }; }
    } else {
      pageResult.mobile = { error: e.message.slice(0, 80) };
    }
  }
  cwvResults.push(pageResult);
  await delay(3000);
}

return [{ json: { cwvResults } }];

const audit = $('Audit All Pages').first().json;
const cwv = $('CWV Fetch').first().json;
const previous = $('Fetch Previous Audit').first().json;

for (const result of audit.results) {
  if (result.status === 'redirect' || result.status === 'error') continue;
  const cwvPage = (cwv.cwvResults || []).find(c => c.url === result.url);
  result.cwv = cwvPage || { mobile: null, desktop: null };
  if (cwvPage?.mobile && !cwvPage.mobile.error) {
    const lcp = cwvPage.mobile.lcp;
    const cls = cwvPage.mobile.cls;
    if (lcp && lcp > 2500) { result.issues.push('LCP_SLOW: ' + Math.round(lcp) + 'ms'); result.score = Math.max(0, result.score - 5); }
    if (cls && cls > 0.1) { result.issues.push('CLS_HIGH: ' + cls.toFixed(3)); result.score = Math.max(0, result.score - 3); }
    if (lcp && lcp <= 2500 && cls !== null && cls <= 0.1) result.score = Math.min(100, result.score + 7);
  }
}

const prevAudit = (previous.previousAudits || [])[0];
let trends = null;
if (prevAudit) {
  const prevResults = prevAudit.results || [];
  const prevByUrl = {};
  for (const pr of prevResults) prevByUrl[pr.url] = pr;
  const active = audit.results.filter(r => r.status !== 'redirect' && r.status !== 'error');
  const activeAvg = active.length ? Math.round(active.reduce((s, r) => s + r.score, 0) / active.length) : 0;
  trends = {
    prevDate: prevAudit.date, prevAvgScore: prevAudit.avg_score,
    scoreDelta: activeAvg - (prevAudit.avg_score || 0),
    issuesDelta: audit.totalIssues - (prevAudit.total_issues || 0),
    pageChanges: []
  };
  for (const result of audit.results) {
    const prev = prevByUrl[result.url];
    if (prev) {
      result.prevScore = prev.score;
      result.scoreDelta = result.score - prev.score;
      result.newIssues = result.issues.filter(i => !(prev.issues || []).includes(i));
      result.resolvedIssues = (prev.issues || []).filter(i => !result.issues.includes(i));
      if (Math.abs(result.scoreDelta) >= 5) trends.pageChanges.push({ name: result.name, url: result.url, from: prev.score, to: result.score, delta: result.scoreDelta });
    } else {
      result.prevScore = null; result.scoreDelta = null;
      result.newIssues = result.issues; result.resolvedIssues = [];
    }
  }
}

const active = audit.results.filter(r => r.status !== 'redirect' && r.status !== 'error');
const avgScore = active.length ? Math.round(active.reduce((s, r) => s + r.score, 0) / active.length) : 0;
const totalIssues = audit.results.reduce((s, r) => s + r.issues.length, 0);
const cwvValid = (cwv.cwvResults || []).filter(c => c.mobile && !c.mobile.error);

return [{ json: {
  ...audit, avgScore, totalIssues,
  cwvSummary: {
    avgMobileLCP: cwvValid.length ? Math.round(cwvValid.reduce((s, c) => s + (c.mobile?.lcp || 0), 0) / cwvValid.length) : null,
    avgMobileCLS: cwvValid.length ? +(cwvValid.reduce((s, c) => s + (c.mobile?.cls || 0), 0) / cwvValid.length).toFixed(3) : null,
    pagesWithSlowLCP: cwvValid.filter(c => c.mobile?.lcp > 2500).length,
    pagesWithHighCLS: cwvValid.filter(c => c.mobile?.cls > 0.1).length,
    pagesChecked: cwvValid.length,
    elapsed: cwv.elapsed
  },
  trends,
  previousWeeks: (previous.previousAudits || []).map(a => ({ date: a.date, avgScore: a.avg_score, issues: a.total_issues }))
}}];

const data = $input.first().json;
const apiKey = $env.ANTHROPIC_API_KEY;
if (!apiKey) return [{ json: { ...data, recommendations: 'ERROR: API key not set' } }];

const resultsForClaude = data.results.filter(r => r.status !== 'redirect').map(r => ({
  url: r.url, name: r.name, score: r.score, prevScore: r.prevScore, scoreDelta: r.scoreDelta,
  issues: r.issues, translationCoverage: r.checks?.translationCoverage,
  gscTop: (r.gscQueries || []).slice(0, 5).map(q => ({ query: q.query, clicks: q.clicks, impressions: q.impressions, ctr: q.ctr, position: q.position, device: q.device })),
  ga4: r.ga4Metrics ? { users: r.ga4Metrics.users, bounce: r.ga4Metrics.bounce } : null,
  cwvMobile: r.cwv?.mobile ? { lcp: r.cwv.mobile.lcp, cls: r.cwv.mobile.cls, perf: r.cwv.mobile.performanceScore } : null
}));

const prompt = `You are an SEO auditor for studiokook.ee (custom kitchen furniture, Tallinn, Estonia). Languages: ET, RU, EN, FI.

Audit: ${data.pageCount} pages, avg score ${data.avgScore}/100, ${data.totalIssues} issues.

## CWV Summary
Avg Mobile LCP: ${data.cwvSummary?.avgMobileLCP || 'N/A'}ms | CLS: ${data.cwvSummary?.avgMobileCLS || 'N/A'}
Slow LCP pages: ${data.cwvSummary?.pagesWithSlowLCP || 0} | High CLS: ${data.cwvSummary?.pagesWithHighCLS || 0}

## Trends
${data.trends ? 'Previous: ' + data.trends.prevDate + ', score ' + data.trends.prevAvgScore + '. Delta: ' + (data.trends.scoreDelta > 0 ? '+' : '') + data.trends.scoreDelta + '. Changes: ' + JSON.stringify(data.trends.pageChanges) : 'No previous data'}

## Per-Page Data
${JSON.stringify(resultsForClaude, null, 1)}

## Task
1. Cross-reference SEO issues with traffic/CWV data
2. Pages with high impressions but low CTR = meta optimization
3. Pages with slow LCP = performance priority
4. Translation gaps affecting international SEO
5. TOP 5 PRIORITY recommendations (most impactful first)
6. Compare with previous week — highlight improvements/regressions
7. Patterns across pages

Rules: RUSSIAN, specific (page+fix+impact), reference metrics, max 500 words, plain text`;

const response = await this.helpers.httpRequest({
  method: 'POST', url: 'https://api.anthropic.com/v1/messages',
  headers: { 'x-api-key': apiKey, 'anthropic-version': '2023-06-01', 'content-type': 'application/json' },
  body: { model: 'claude-sonnet-4-20250514', max_tokens: 3000, messages: [{ role: 'user', content: prompt }] }
});

return [{ json: { ...data, recommendations: response.content[0].text } }];

const audit = $input.first().json;
const url = $env.SUPABASE_URL;
const key = $env.SUPABASE_SERVICE_ROLE_KEY;
if (!url || !key) return [{ json: { ...audit, supabaseError: 'SUPABASE_URL or KEY not set' } }];

try {
  const resp = await this.helpers.httpRequest({
    method: 'POST', url: url + '/rest/v1/audit_results',
    headers: { 'apikey': key, 'Authorization': 'Bearer ' + key, 'Content-Type': 'application/json', 'Prefer': 'return=representation,resolution=merge-duplicates' },
    body: { type: 'seo', date: audit.date, avg_score: audit.avgScore, total_issues: audit.totalIssues, page_count: audit.pageCount, results: audit.results, recommendations: audit.recommendations || '' }
  });
  audit.supabaseId = resp[0]?.id || 'saved';
} catch(e) { audit.supabaseError = e.message.slice(0, 200); }

try {
  const pageScoreRows = audit.results.filter(r => r.status !== 'redirect' && r.status !== 'error').map(r => ({
    audit_type: 'seo', date: audit.date, page_url: r.url, page_name: r.name, score: r.score,
    issue_count: r.issues.length,
    cwv_lcp_mobile: r.cwv?.mobile?.lcp || null, cwv_cls_mobile: r.cwv?.mobile?.cls || null,
    cwv_perf_mobile: r.cwv?.mobile?.performanceScore || null,
    translation_coverage: r.checks?.translationCoverage || null,
    hreflang_ok: (r.checks?.missingHreflang || []).length === 0
  }));
  await this.helpers.httpRequest({
    method: 'POST', url: url + '/rest/v1/audit_page_scores',
    headers: { 'apikey': key, 'Authorization': 'Bearer ' + key, 'Content-Type': 'application/json', 'Prefer': 'resolution=merge-duplicates' },
    body: pageScoreRows
  });
} catch(e) { /* non-fatal */ }

return [{ json: audit }];

const data = $input.first().json;
const results = (data.results || []).filter(r => r.status !== 'redirect' && r.status !== 'error');

let md = '---\ntype: seo-audit\ndate: ' + data.date + '\navgScore: ' + data.avgScore + '\ntotalIssues: ' + data.totalIssues + '\npageCount: ' + data.pageCount + '\n---\n\n';
md += '# SEO Audit: ' + data.date + '\n\n';
md += '## Summary\n\n';
md += '| Metric | Value |\n|--------|-------|\n';
md += '| Score | **' + data.avgScore + '/100** |\n';
md += '| Pages | ' + data.pageCount + ' |\n';
md += '| Issues | ' + data.totalIssues + ' |\n';

if (data.trends) {
  md += '| Prev Score | ' + data.trends.prevAvgScore + ' (' + (data.trends.scoreDelta >= 0 ? '+' : '') + data.trends.scoreDelta + ') |\n';
}

if (data.cwvSummary && data.cwvSummary.avgMobileLCP) {
  md += '| Avg LCP | ' + (data.cwvSummary.avgMobileLCP / 1000).toFixed(1) + 's |\n';
  md += '| Avg CLS | ' + data.cwvSummary.avgMobileCLS + ' |\n';
  md += '| Slow LCP pages | ' + data.cwvSummary.pagesWithSlowLCP + ' |\n';
}

const translated = results.filter(r => r.checks?.translationCoverage === 100).length;
md += '| Translations | ' + translated + '/' + results.length + ' (' + Math.round(translated/results.length*100) + '%) |\n';
md += '\n';

// Trends
if (data.trends?.pageChanges?.length) {
  md += '## Changes vs Previous Week\n\n';
  const improved = data.trends.pageChanges.filter(c => c.delta > 0);
  const degraded = data.trends.pageChanges.filter(c => c.delta < 0);
