md += '\n';

// Trends
if (data.trends?.pageChanges?.length) {
  md += '## Changes vs Previous Week\n\n';
  const improved = data.trends.pageChanges.filter(c => c.delta > 0);
  const degraded = data.trends.pageChanges.filter(c => c.delta < 0);
  if (improved.length) { md += '**Improved:**\n'; improved.forEach(c => md += '- ' + c.name + ': ' + c.from + ' -> ' + c.to + ' (+' + c.delta + ')\n'); md += '\n'; }
  if (degraded.length) { md += '**Degraded:**\n'; degraded.forEach(c => md += '- ' + c.name + ': ' + c.from + ' -> ' + c.to + ' (' + c.delta + ')\n'); md += '\n'; }
