  const emoji = r.score >= 80 ? '\u2705' : r.score >= 60 ? '\u26A0\uFE0F' : '\u274C';
  md += '| ' + emoji + ' ' + r.name + ' | ' + r.score + delta + ' | ' + r.issues.length + ' | ' + (r.ga4Metrics?.users || 0) + ' | ' + (r.checks?.translationCoverage || 0) + '% |\n';
}
md += '\n';

